package controller;import model.Grupo;import model.User;public class ControllerGrupos {    /*    GRUPO: FP        SUBGRUPO: DAM            user1            user2            user3        SUBGRUPO: DAW            user4            user5            user6     */    public boolean perteneceA(Grupo grupo, User user){        if (grupo.getUsers().contains(user)){            return true;        } else {            for (Grupo subgrupo : grupo.getSubGrupos()){               return perteneceA(subgrupo, user);            }        }        return false;    }}